import{_ as e,r as o,o as a,c as i,e as g,d as s,f as c}from"./app-f284a942.js";const r={},n=c('<p>PS 中效果（加了黑色背景方便对比）：</p><figure><img src="https://img-blog.csdnimg.cn/20200702031653956.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3FxXzI4Mzk4MzAx,size_16,color_FFFFFF,t_70" alt="在这里插入图片描述" tabindex="0" loading="lazy"><figcaption>在这里插入图片描述</figcaption></figure><p>游戏编辑器中实际效果：</p><figure><img src="https://img-blog.csdnimg.cn/20200702031800163.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3FxXzI4Mzk4MzAx,size_16,color_FFFFFF,t_70" alt="在这里插入图片描述" tabindex="0" loading="lazy"><figcaption>在这里插入图片描述</figcaption></figure><p>看到这里大家是不是很熟悉，只要加个循环旋转动画就能让它动起来了，哈哈</p><p>那么来说下实现流程：</p><p>#. 新建一个 500*500 透明图层（大小可以自己调整）<br> #. 菜单栏-&gt;图层-&gt;新建填充图层-&gt;渐变-&gt;黑白渐变-&gt;<br><img src="https://img-blog.csdnimg.cn/20200702034020540.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3FxXzI4Mzk4MzAx,size_16,color_FFFFFF,t_70" alt="在这里插入图片描述" loading="lazy"></p><p>点击左上角的小方块-&gt;调整不透明度为 0-&gt;点击右上角的小方块-&gt;调整不透明度为 80（也可以不调整右边，会更加明亮）<br> #. 菜单栏-&gt;滤镜-&gt;扭曲-&gt;波浪-&gt;提示转为智能对象(选择是)-&gt;调整为如下数值（具体效果可以自己调整看看）</p><figure><img src="https://img-blog.csdnimg.cn/20200702034357293.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3FxXzI4Mzk4MzAx,size_16,color_FFFFFF,t_70" alt="在这里插入图片描述" tabindex="0" loading="lazy"><figcaption>在这里插入图片描述</figcaption></figure><p>#. 菜单栏-&gt;滤镜-&gt;扭曲-&gt;极坐标<br> 完成，自己导出使用就好了，如果不知道怎么调色彩，直接在游戏引擎里面调就好了，白色图万能</p><hr><h3>📣 觉得很赞？分享给你的朋友吧！</h3>',12);function p(m,_){const t=o("Share");return a(),i("div",null,[g(" more "),n,s(t,{services:"qq,qrcode",colorful:""})])}const F=e(r,[["render",p],["__file","2.html.vue"]]);export{F as default};
